import fs from 'node:fs';
import path from 'node:path';

const file = fs.readFileSync(path.join(import.meta.dirname, 'file.js'), 'utf8');
const matches = file.replace(/strings\[([a-z0-9]+)\]/g, (match, group1) => {
    const string = strings[Number(group1)];
    return string.includes('\n') ? `\`${strings[Number(group1)].replaceAll(/"/g, '\\"')}\`` : `"${strings[Number(group1)].replaceAll(/"/g, '\\"')}"`;
});
fs.writeFileSync(path.join(import.meta.dirname, 'file.js'), matches, 'utf8');